CustomField.formula:
TEXT( 
FLOOR(Opp_Closed_Date_Time__c  -  Account.Lead_Created_Date_Time__c) 
) & " Days " & 
TEXT( 
FLOOR(MOD((Opp_Closed_Date_Time__c  -  Account.Lead_Created_Date_Time__c)*24,24)) 
) &" Hours " & 
TEXT( 
ROUND(MOD((Opp_Closed_Date_Time__c  -  Account.Lead_Created_Date_Time__c)*1440,60),0) 
) &" Minutes "
